import React, { useState, useEffect } from 'react';

const TableComponent = () => {
    const [records, setRecords] = useState([
        { id: 1, name: 'adam', age: 25 },
        { id: 2, name: 'james', age: 30 },
        { id: 3, name: 'nick', age: 28 },
        { id: 4, name: 'john', age: 29 }
    ]);
    const [filter, setFilter] = useState('');
    const [sortField, setSortField] = useState('name');
    const [sortOrder, setSortOrder] = useState('asc');

    // Filter function
    const filteredRecords = () => {
        const lowerFilter = filter.toLowerCase();
        return records.filter(record => 
            record.name.toLowerCase().includes(lowerFilter)
        );
    };

    // Sort function
    const sortedRecords = () => {
        return [...filteredRecords()].sort((a, b) => {
            if (sortOrder === 'asc') {
                return a[sortField].localeCompare(b[sortField]);
            } else {
                return b[sortField].localeCompare(a[sortField]);
            }
        });
    };

    // Update records on filter or sort change
    useEffect(() => {
        setRecords(sortedRecords());
    }, [filter, sortField, sortOrder]);

    return (
        <div>
            <input
                type="text"
                placeholder="Filter by name..."
                value={filter}
                onChange={(e) => setFilter(e.target.value)}
                className="filter-input"
            />
            <table className="table">
                <thead>
                    <tr>
                        <th onClick={() => setSortField('id')}>id</th>
                        <th onClick={() => setSortField('name')}>name</th>
                        <th onClick={() => setSortField('age')}>age</th>
                    </tr>
                </thead>
                <tbody>
                    {sortedRecords().map(record => (
                        <tr key={record.id}>
                            <td>{record.id}</td>
                            <td>{record.name}</td>
                            <td>{record.age}</td>
                        </tr>
                    ))}
                </tbody>
            </table>
        </div>
    );
};

export default TableComponent;
